head.script:
/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	scwin.param = JSON.parse($p.getPopupParam());
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSME1100000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 착공일 초기설정
	scwin.initSearchParam();
	// 데이터 조회
	if (dmaSearchParam.get("deptCd")) {
		scwin.btnInqire_onclick();
	}
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	dmaSearchParam.setJSON(scwin.param);
	dmaSearchParam.set("deptCdOld", dmaSearchParam.get("deptCd"));
	acbChrgDept.setValue(dmaSearchParam.get("deptCd").padStart(10, "0"));
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = async function() {
	var deptCd = dmaSearchParam.get("deptCd");
	dmaSearchParam.set("deptCdOld", deptCd);
	if (!deptCd || deptCd == "") {
		// 담당부서를 선택해주세요.
		comLib.alert($p, "담당부서를 선택해주세요.");
		return;
	}
	var fetchArr = [
		scwin.inqireRfc().then(scwin.inqireRfcCallback), // RFC API
		scwin.inqireBudgetExcut() // ECS 예산집행
	];
	await Promise.all(fetchArr);

	var budgetExcutDatas = dltBudgetExcutList.getAllJSON();
	var budgetExcutRfcDatas = dltBudgetExcutRfcList.getAllJSON();
	var vobelnrArr = [...new Set(budgetExcutDatas.flatMap(obj => obj.slipNo))];
	budgetExcutRfcDatas.forEach((obj, idx) => {
		if (vobelnrArr.includes(`${obj.VOBELNR}_${obj.KNBUZEI}`)) {
			dltBudgetExcutRfcList.setCellData(idx, "CHK", "Y");
			dltBudgetExcutRfcList.modifyRowStatus(idx, "R");
		}
	});

	budgetExcutRfcDatas = dltBudgetExcutRfcList.getAllJSON();
	budgetExcutRfcDatas.forEach((obj, idx) => {
		if (obj.CHK == "Y") {
			var isDiff = budgetExcutDatas.find(excutObj => excutObj.slipNo == `${obj.VOBELNR}_${obj.KNBUZEI}` && excutObj.excutAmt != obj.TRBTR_C);
			if (isDiff) {
				grdBudgetExcutList.setCellColor(idx, "TRBTR_C", "#0000FF");
				dltBudgetExcutRfcList.modifyRowStatus(idx, "U");
			}
		}
	});
};

scwin.inqireRfc = function() {
	return new Promise((resolve, rejext) => {
		var gjahr = dmaSearchParam.get("strtDt");
		var fistl = dmaSearchParam.get("deptCd");

		var requestData = {
			"RFC_NAME" : "ZFMZ_REPORT_002",
			"IS_IMPORT" : {
				"CRUD_GUBUN" : "R",
				"KSYS_ID" : "ECS",
				"IF_EMP_ID" : "60002524"
			},
			"IS_CON2" : {
				"FIKRS" : "KW00",
				"FIPEX" : "6155031",
				"FIPEX_GRP" : "6155000",
				"FISTL" : fistl,
				"FKBER" : ["5230", "5250"],
				"GJAHR" : gjahr,
				"GUBUN" : "A",
				"MEASURE" : "",
				"MEASURE_TXT" : "",
				"PERIOD_F" : "202301",
				"PERIOD_T" : "202312"
			}
		};

		var option = {
			action : "zz/cmmn/retrieve-rfc.do",
			method : "post",
			reqData : requestData,
			resData : dltBudgetExcutRfcList,
			success : function() {
				resolve();
			},
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	});
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireRfcCallback = function() {
	spnTotalRow.setValue(dltBudgetExcutRfcList.getRowCount());
};

scwin.inqireBudgetExcut = function() {
	return new Promise((resolve, rejext) => {
		var strtDt = dmaSearchParam.get("strtDt");
		var ecsChrgDeptId = dmaSearchParam.get("deptCd");

		var queryString = `?strtDt=${strtDt}`;
		queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;

		var option = {
			action : "me/mntmng/retrieve-budget-excut.do"
				+ queryString,
			method : "get",
			reqData : "",
			resData : dltBudgetExcutList,
			success : function() {
				resolve();
			},
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	});
};

/**
 * 셀을 선택 후 선택 버튼 클릭시 해당 내용을 상세내역으로 표출한다.
 * @param
 * @return
 */
scwin.btnSave_onclick = function() {
	if (btnSave.hasClass("hide")) {
		return;
	}
	if (dltBudgetExcutRfcList.getAllJSON().filter(obj => obj.rowStatus != "R").length > 0) {
		// 변경된 내역이 있습니다.\n저장 하시겠습니까? \n수정사유를 입력하세요.
		ecsLib.saveRsn($p, `${dltBudgetExcutRfcList.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00239")[0], "scwin.saveConfirmCallback");
	} else {
		// 처리할 데이터가 없습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
	}
};

/**
 * 등록 ComfirmCallBack 실행한다.
 * @param
 * @return
 */
scwin.saveConfirmCallback = function() {
	var initDataList = dltBudgetExcutRfcList.getAllJSON().filter(obj => obj.rowStatus != "R");

	for (data of initDataList) {
		var newObj = {
			"slipNo" : `${data.VOBELNR}_${data.KNBUZEI}`,
			"ecsChrgDeptId" : dmaSearchParam.get("deptCdOld"),
			"iemTitCtnt" : data.ZZTITCNT,
			"entrpsNm" : data.LIFNR_T,
			"slipPstde" : data.ZHLDT,
			"excutAmt" : data.TRBTR_C,
			"sumAmt" : Number(data.TRBTR_C) * 1.1,
			"chargerId" : data.PERNR,
			"updtRsn" : data.updtRsn,
		};

		var newIdx = dltBudgetExcutSaveList.insertRow();
		dltBudgetExcutSaveList.setRowJSON(newIdx, newObj, true);
		dltBudgetExcutSaveList.modifyRowStatus(newIdx, data.CHK == "N" ? "E" : "U");
	}
	var requestData = {};
	requestData.dltBudgetExcutList = dltBudgetExcutSaveList.getAllJSON();

	var option = {
		action : "me/mntmng/process-budget-excut.do",
		reqData : requestData,
		success : "scwin.saveMsgCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 저장 확인 콜백
 * @param
 * @return
 */
scwin.saveMsgCallback = function(res) {
	// 모달 창 닫기
	setTimeout(() => {
		var deptCd = dmaSearchParam.get("deptCdOld");
		$p.parent().scwin.grdFocusedDeptCd = deptCd;
		$p.parent().scwin.saveMsgCallback(res);
		$p.closePopup();
	}, 100);
};

/**
 * 부서 변경 이벤트
 * @param
 * @return
 */
scwin.acbChrgDept_onviewchange = function(info) {
	var deptCd = info.newValue;
	dmaSearchParam.set("deptCd", (deptCd || "").substr(-4));
};

/**
 * 그리드뷰 더블클릭 이벤트
 * @param
 * @return
 */
scwin.grdBudgetExcutList_oncelldblclick = function(row, col, colId) {
	if (!grdBudgetExcutList.getCellDisabled(row, 0)) {
		grdBudgetExcutList.setCellChecked(row, 0, true);
		scwin.btnSave_onclick();
	}
};

// 초기로드후 체크박스 체크해제시 rowStatus 변경 안됨 및 체크해제시 rowStatus U이므로 E 변경
scwin.dltBudgetExcutRfcList_oncelldatachange = function(info) {
	if (info.colID == "CHK") {
		if (info.oldValue == "N" && info.newValue == "Y") {
			dltBudgetExcutRfcList.modifyRowStatus(info.rowIndex, "C");
		} else {
			dltBudgetExcutRfcList.modifyRowStatus(info.rowIndex, "E");
		}
	};
};
